
.dashboard-shell {
  width: 100%;
  max-width: 980px;
  margin: 0 auto;
  display: flex;
  flex-direction: column;
  background:
    radial-gradient(circle at top right, rgba(166, 70, 48, 0.12), transparent 42%),
    linear-gradient(180deg, var(--c-panel), var(--c-bg));
  border: 1px solid rgba(111, 78, 55, 0.32);
  border-radius: 16px;
  overflow: hidden;
  box-shadow: var(--shadow-panel);
}

.content-area {
  display: flex;
  flex-direction: column;
  gap: 10px;
  padding: 10px;
}

.world-overview {
  display: grid;
  gap: 10px;
}

.world-hero-grid {
  display: grid;
  grid-template-columns: minmax(0, 1.2fr) minmax(320px, 0.9fr);
  gap: 10px;
  align-items: start;
}

@media (max-width: 900px) {
  .world-hero-grid {
    grid-template-columns: 1fr;
  }
}
