
.history-layout {
  display: grid;
  gap: 12px;
}

.panel-card {
  padding: 14px;
  border-radius: 14px;
  background: rgba(255, 250, 241, 0.78);
  border: 1px solid rgba(111, 78, 55, 0.14);
}

.hero-card {
  background: linear-gradient(180deg, rgba(111, 84, 125, 0.08), transparent 60%), rgba(255, 250, 241, 0.82);
}

.section-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 10px;
  margin-bottom: 12px;
}

.section-title {
  font-size: 0.92rem;
  font-weight: 700;
  color: var(--c-text);
}

.pill {
  padding: 3px 8px;
  border-radius: 999px;
  font-size: 0.72rem;
  background: rgba(111, 78, 55, 0.06);
  color: var(--c-muted);
}

.accent {
  color: var(--c-purple);
  background: rgba(111, 84, 125, 0.1);
}

.safe {
  color: var(--c-green);
  background: rgba(87, 107, 61, 0.1);
}

.danger {
  color: var(--c-red);
  background: rgba(140, 48, 48, 0.1);
}

.summary-grid,
.route-grid,
.log-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
}

.summary-card,
.route-card,
.log-card {
  padding: 12px;
  border-radius: 12px;
  background: rgba(248, 240, 225, 0.82);
  border: 1px solid rgba(111, 78, 55, 0.12);
}

.summary-label,
.log-title,
.route-name {
  display: block;
  font-size: 0.76rem;
  color: var(--c-muted);
  margin-bottom: 4px;
}

.summary-value {
  font-size: 0.94rem;
  font-weight: 700;
  color: var(--c-text);
}

.summary-value.small {
  font-size: 0.82rem;
  line-height: 1.45;
}

.pressure-list {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
}

.pressure-item {
  padding: 12px;
  border-radius: 12px;
  background: rgba(248, 240, 225, 0.82);
  border: 1px solid rgba(111, 78, 55, 0.12);
}

.pressure-head {
  display: flex;
  justify-content: space-between;
  gap: 10px;
  font-size: 0.78rem;
  color: var(--c-muted);
  margin-bottom: 8px;
}

.pressure-head strong {
  color: var(--c-text);
}

.progress-track {
  width: 100%;
  height: 8px;
  border-radius: 999px;
  overflow: hidden;
  background: rgba(111, 78, 55, 0.12);
}

.progress-fill {
  height: 100%;
  border-radius: inherit;
}

.log-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.log-row {
  display: flex;
  flex-direction: column;
  gap: 4px;
  font-size: 0.76rem;
  color: var(--c-muted);
}

.warning-list {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.warning-tag {
  padding: 3px 8px;
  border-radius: 999px;
  background: rgba(140, 48, 48, 0.1);
  color: var(--c-red);
  font-size: 0.72rem;
}

.empty-text {
  font-size: 0.76rem;
  color: var(--c-muted);
}

@media (max-width: 720px) {
  .summary-grid,
  .route-grid,
  .log-grid,
  .pressure-list {
    grid-template-columns: 1fr;
  }
}
