
.event-layout {
  display: grid;
  gap: 12px;
}

.panel-card {
  padding: 14px;
  border-radius: 14px;
  background: rgba(255, 250, 241, 0.78);
  border: 1px solid rgba(111, 78, 55, 0.14);
}

.section-head {
  margin-bottom: 12px;
}

.section-title {
  font-size: 0.92rem;
  font-weight: 700;
  color: var(--c-text);
}

.timeline {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.timeline-node {
  display: grid;
  grid-template-columns: 16px minmax(0, 1fr);
  gap: 10px;
  align-items: start;
}

.dot {
  width: 12px;
  height: 12px;
  border-radius: 50%;
  margin-top: 6px;
  background: rgba(111, 78, 55, 0.18);
}

.dot.accent {
  background: var(--c-accent);
}

.dot.warn {
  background: var(--c-orange);
}

.node-body {
  padding: 10px 12px;
  border-radius: 12px;
  background: rgba(248, 240, 225, 0.82);
  border: 1px solid rgba(111, 78, 55, 0.12);
}

.node-head {
  display: flex;
  justify-content: space-between;
  gap: 8px;
  align-items: center;
}

.node-title {
  font-weight: 700;
  color: var(--c-text);
}

.node-sub {
  margin-top: 6px;
  font-size: 0.76rem;
  color: var(--c-muted);
}

.pill {
  padding: 3px 8px;
  border-radius: 999px;
  font-size: 0.72rem;
  background: rgba(111, 78, 55, 0.06);
  color: var(--c-muted);
}

.pill.accent {
  background: rgba(143, 45, 45, 0.1);
  color: var(--c-accent);
}

.pill.warn {
  background: rgba(168, 94, 50, 0.1);
  color: var(--c-orange);
}

.future-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 10px;
}

.future-card {
  display: flex;
  flex-direction: column;
  gap: 4px;
  padding: 12px;
  border-radius: 12px;
  background: rgba(248, 240, 225, 0.82);
  border: 1px solid rgba(111, 78, 55, 0.12);
}

.future-title {
  font-weight: 700;
  color: var(--c-text);
}

.future-status {
  font-size: 0.76rem;
  color: var(--c-muted);
}

@media (max-width: 720px) {
  .future-grid {
    grid-template-columns: 1fr;
  }
}
