
.metrics-grid {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 8px;
}

.metric-card {
  display: grid;
  gap: 6px;
  padding: 8px 9px;
  border-radius: 10px;
  background: rgba(248, 240, 225, 0.82);
  border: 1px solid rgba(111, 78, 55, 0.1);
}

.metric-topline {
  display: flex;
  justify-content: space-between;
  gap: 6px;
  align-items: center;
}

.metric-label {
  font-size: 0.68rem;
  color: var(--c-muted);
}

.metric-value {
  font-size: 0.82rem;
  font-weight: 700;
  color: var(--c-text);
}

.progress-track {
  width: 100%;
  height: 5px;
  border-radius: 999px;
  overflow: hidden;
  background: rgba(111, 78, 55, 0.12);
}

.progress-fill {
  height: 100%;
  border-radius: inherit;
  transition: width 0.25s ease;
}

.accent {
  background: linear-gradient(90deg, rgba(193, 139, 69, 0.95), rgba(143, 45, 45, 0.8));
}

.green {
  background: linear-gradient(90deg, rgba(87, 107, 61, 0.92), rgba(132, 151, 80, 0.82));
}

.yellow {
  background: linear-gradient(90deg, rgba(182, 138, 45, 0.9), rgba(210, 169, 84, 0.78));
}

.orange {
  background: linear-gradient(90deg, rgba(168, 94, 50, 0.9), rgba(193, 139, 69, 0.82));
}

.red {
  background: linear-gradient(90deg, rgba(140, 48, 48, 0.92), rgba(186, 75, 75, 0.84));
}

.cyan {
  background: linear-gradient(90deg, rgba(68, 101, 110, 0.92), rgba(100, 136, 146, 0.82));
}

.purple {
  background: linear-gradient(90deg, rgba(111, 84, 125, 0.92), rgba(151, 118, 168, 0.82));
}

@media (max-width: 860px) {
  .metrics-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 520px) {
  .metrics-grid {
    grid-template-columns: 1fr;
  }
}
