
.faction-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 12px;
}

.panel-card {
  padding: 14px;
  border-radius: 14px;
  background: rgba(255, 250, 241, 0.78);
  border: 1px solid rgba(111, 78, 55, 0.14);
}

.section-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 10px;
  margin-bottom: 12px;
}

.section-title {
  font-size: 0.9rem;
  font-weight: 700;
  color: var(--c-text);
}

.pill {
  padding: 3px 8px;
  border-radius: 999px;
  font-size: 0.72rem;
}

.neutral {
  color: var(--c-muted);
  background: rgba(111, 78, 55, 0.06);
}

.warn {
  color: var(--c-orange);
  background: rgba(168, 94, 50, 0.1);
}

.danger {
  color: var(--c-red);
  background: rgba(140, 48, 48, 0.1);
}

.stat-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.stat-row {
  display: flex;
  justify-content: space-between;
  gap: 10px;
  padding-bottom: 6px;
  border-bottom: 1px dashed rgba(111, 78, 55, 0.12);
  font-size: 0.8rem;
  color: var(--c-muted);
}

.stat-row strong {
  color: var(--c-text);
}

@media (max-width: 720px) {
  .faction-grid {
    grid-template-columns: 1fr;
  }
}
