
.world-layout {
  display: grid;
  gap: 10px;
  height: 100%;
}

.panel-card,
.task-section {
  padding: 10px;
  background: rgba(255, 250, 241, 0.74);
  border: 1px solid rgba(111, 78, 55, 0.14);
  border-radius: 12px;
}

.hero-card {
  background: linear-gradient(180deg, rgba(193, 139, 69, 0.08), transparent 64%), rgba(255, 250, 241, 0.82);
}

.world-bulletin-card {
  overflow: hidden;
}

.head-row,
.section-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 8px;
  margin-bottom: 8px;
}

.section-title {
  font-size: 0.9rem;
  font-family: var(--font-heading);
  font-weight: 700;
  color: var(--c-text);
}

.section-sub {
  font-size: 0.68rem;
  color: var(--c-muted);
  margin-top: 1px;
}

.stage-pill,
.section-badge {
  display: inline-flex;
  align-items: center;
  padding: 3px 8px;
  border-radius: 999px;
  font-size: 0.68rem;
  font-weight: 700;
  line-height: 1.1;
}

.stage-pill {
  background: rgba(143, 45, 45, 0.1);
  color: var(--c-accent);
  border: 1px solid rgba(143, 45, 45, 0.16);
}

.section-badge {
  background: rgba(68, 101, 110, 0.1);
  color: var(--c-cyan);
  border: 1px solid rgba(68, 101, 110, 0.12);
}

.bulletin-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 8px;
}

.focus-item {
  grid-column: 1 / -1;
}

.meta-item {
  display: flex;
  flex-direction: column;
  gap: 2px;
  padding: 9px 10px;
  border-radius: 10px;
  background: rgba(248, 240, 225, 0.84);
  border: 1px solid rgba(111, 78, 55, 0.1);
  min-width: 0;
}

.meta-label {
  font-size: 0.66rem;
  color: var(--c-muted);
}

.meta-value {
  font-size: 0.86rem;
  font-weight: 700;
  color: var(--c-text);
}

.meta-sub {
  font-size: 0.68rem;
  color: var(--c-muted);
  line-height: 1.25;
}

.tag-list {
  display: flex;
  flex-wrap: wrap;
  gap: 5px;
}

.tag {
  display: inline-flex;
  align-items: center;
  max-width: 100%;
  padding: 2px 7px;
  border-radius: 999px;
  background: rgba(68, 101, 110, 0.12);
  color: var(--c-cyan);
  font-size: 0.66rem;
  line-height: 1.15;
}

.muted-tag {
  color: var(--c-muted);
  background: rgba(111, 78, 55, 0.06);
}

.compact-section {
  padding-top: 9px;
}

.compact-head {
  margin-bottom: 7px;
}

.compact-task-row {
  display: grid;
  gap: 6px;
}

.compact-task-card {
  display: grid;
  gap: 3px;
  padding: 8px 10px;
  border-radius: 10px;
  background: rgba(245, 232, 212, 0.82);
  border-left: 3px solid rgba(193, 139, 69, 0.7);
}

.task-name {
  font-size: 0.76rem;
  font-weight: 700;
  color: var(--c-text);
}

.task-desc {
  font-size: 0.68rem;
  color: var(--c-muted);
  line-height: 1.3;
}

@media (max-width: 720px) {
  .bulletin-grid {
    grid-template-columns: 1fr;
  }

  .head-row,
  .section-head {
    flex-direction: column;
    align-items: flex-start;
  }
}
