
.quickfeed-layout {
  display: grid;
  gap: 8px;
  height: 100%;
}

.section-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 8px;
}

.section-title {
  font-size: 0.86rem;
  font-family: var(--font-heading);
  font-weight: 700;
  color: var(--c-text);
}

.section-sub {
  margin-top: 1px;
  font-size: 0.66rem;
  color: var(--c-muted);
}

.section-badge {
  display: inline-flex;
  align-items: center;
  padding: 3px 8px;
  border-radius: 999px;
  font-size: 0.66rem;
  font-weight: 700;
  background: rgba(68, 101, 110, 0.1);
  color: var(--c-cyan);
  border: 1px solid rgba(68, 101, 110, 0.12);
}

.alerts-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 8px;
}

.alert-card {
  display: grid;
  gap: 4px;
  padding: 9px 10px;
  border-radius: 10px;
  background: rgba(248, 240, 225, 0.82);
  border: 1px solid rgba(111, 78, 55, 0.1);
}

.feature-card {
  background: linear-gradient(180deg, rgba(193, 139, 69, 0.08), transparent 72%), rgba(248, 240, 225, 0.9);
}

.danger-card {
  background: linear-gradient(180deg, rgba(140, 48, 48, 0.08), transparent 72%), rgba(248, 240, 225, 0.9);
}

.alert-topline {
  display: flex;
  justify-content: space-between;
  gap: 6px;
  align-items: center;
}

.alert-label {
  font-size: 0.66rem;
  color: var(--c-muted);
}

.alert-title {
  font-size: 0.78rem;
  font-weight: 700;
  color: var(--c-text);
  line-height: 1.15;
}

.alert-sub {
  font-size: 0.66rem;
  color: var(--c-muted);
  line-height: 1.2;
}

.pill {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 2px 7px;
  border-radius: 999px;
  font-size: 0.64rem;
  line-height: 1.1;
  border: 1px solid rgba(111, 78, 55, 0.14);
}

.accent {
  color: var(--c-accent);
  background: rgba(143, 45, 45, 0.08);
}

.neutral {
  color: var(--c-muted);
  background: rgba(111, 78, 55, 0.06);
}

.safe {
  color: var(--c-green);
  background: rgba(87, 107, 61, 0.1);
}

.warn {
  color: var(--c-orange);
  background: rgba(168, 94, 50, 0.1);
}

.danger {
  color: var(--c-red);
  background: rgba(140, 48, 48, 0.1);
}

@media (max-width: 520px) {
  .section-head {
    flex-direction: column;
    align-items: flex-start;
  }

  .alerts-grid {
    grid-template-columns: 1fr;
  }
}
