
.topbar {
  display: flex;
  flex-direction: column;
  gap: 8px;
  padding: 10px 10px 8px;
  background:
    radial-gradient(circle at top right, rgba(143, 45, 45, 0.14), transparent 46%),
    linear-gradient(180deg, rgba(72, 45, 24, 0.92), rgba(72, 45, 24, 0.82));
  border-bottom: 1px solid rgba(255, 244, 230, 0.12);
}

.topbar-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
}

.brand {
  display: flex;
  align-items: center;
  gap: 8px;
  min-width: 0;
}

.icon {
  font-size: 1.16rem;
  line-height: 1;
}

.title {
  color: #fff8ef;
  font-family: var(--font-heading);
  font-size: 0.98rem;
  font-weight: 700;
  letter-spacing: 0.03em;
}

.subtitle {
  color: rgba(255, 244, 230, 0.72);
  font-size: 0.7rem;
  margin-top: 1px;
}

.meta-box {
  display: flex;
  flex-direction: column;
  gap: 1px;
  padding: 6px 10px;
  border-radius: 10px;
  background: rgba(255, 248, 239, 0.08);
  border: 1px solid rgba(255, 244, 230, 0.14);
  color: #fff8ef;
  white-space: nowrap;
  text-align: right;
}

.meta-main {
  font-size: 0.74rem;
  font-weight: 700;
}

.meta-sub {
  font-size: 0.66rem;
  color: rgba(255, 244, 230, 0.72);
}

.tabs {
  display: flex;
  align-items: stretch;
  background: rgba(255, 248, 239, 0.08);
  border: 1px solid rgba(255, 244, 230, 0.14);
  border-radius: 10px;
  overflow-x: auto;
  scrollbar-width: none;
}

.tabs::-webkit-scrollbar {
  display: none;
}

.tab-button {
  appearance: none;
  border: none;
  background: transparent;
  color: rgba(255, 244, 230, 0.72);
  padding: 8px 12px;
  min-width: 84px;
  cursor: pointer;
  font-size: 0.78rem;
  letter-spacing: 0.03em;
  border-right: 1px solid rgba(255, 244, 230, 0.08);
  transition: 0.18s ease;
  flex: 1 0 auto;
}

.tab-button:last-child {
  border-right: none;
}

.tab-button:hover {
  color: #fff8ef;
  background: rgba(255, 248, 239, 0.08);
}

.tab-button.active {
  color: #fff8ef;
  background: linear-gradient(180deg, rgba(193, 139, 69, 0.32), rgba(143, 45, 45, 0.16));
  box-shadow: inset 0 -1px 0 rgba(255, 248, 239, 0.52);
}

@media (max-width: 640px) {
  .topbar-head {
    flex-direction: column;
    align-items: flex-start;
  }

  .meta-box {
    align-self: stretch;
    text-align: left;
  }
}

@media (max-width: 480px) {
  .subtitle {
    display: none;
  }
}
